// ================= SAFE INPUT =================
const chat = $node["WhatsApp Trigger3"].json;

let rawMessage = "";
const msg = chat.messages?.[0];

if (msg?.type === "text") {
  rawMessage = msg.text?.body || "";
}
else if (msg?.type === "interactive") {
  rawMessage = msg.interactive?.button_reply?.id || "";
}

if (typeof rawMessage === "object") {
  rawMessage = rawMessage?.text || rawMessage?.value || "";
}

const message = String(rawMessage).trim();
const lowerMessage = message.toLowerCase();
const phone = chat.messages?.[0]?.from || "unknown_user";

// ================= SHEET DATA =================
const items = $input.all();

let row = {};
let normalizedPhone = phone.slice(-10);

let filteredItems = items.filter(item => {
  let sheetPhone = String(item.json.phone || "").slice(-10);
  return sheetPhone === normalizedPhone;
});

if (filteredItems.length > 0) {
  filteredItems.sort((a, b) => {
    return new Date(b.json.updated_at) - new Date(a.json.updated_at);
  });
  row = filteredItems[0].json;
}

// ================= FORCE RESET ON HI =================
if (["hi","hello","start","restart"].includes(lowerMessage)) {

  const newSessionId = `${phone}_${Date.now()}`;

  return [
    {
      json: {
        user_id: newSessionId,
        phone: phone,
        state: "main_menu",
        updated_at: new Date().toISOString(),
        response:
          "🙏 *Welcome to Traket Transport* 🚛\n\n" +
          "We provide reliable logistics solutions across India 🇮🇳\n\n" +
          "👉 Please select your requirement:\n\n" +
          "1️⃣ Book a Vehicle (Customer)\n" +
          "2️⃣ Provide Vehicle (Transporter)\n" +
          "3️⃣ Support\n\n" +
          "Reply with *1, 2 or 3*",
        flowType: "",
        data: "{}"
      }
    }
  ];
}

// ================= OPTION MAPPINGS =================
const vehicleTypeMap = {
  "1": "Tempo",
  "2": "Truck",
  "3": "Container",
  "4": "Trailer / ODC"
};

const cargoTypeMap = {
  "1": "Domestic",
  "2": "Import",
  "3": "Export"
};

const vehicleCategoryMap = {
  "tempo_type": "Tempo",
  "truck_type": "Truck",
  "container_type": "Container"
};

const tempoSubTypeMap = {
  "1": "Pickup – 1 MT (8×5×5 ft)",
  "2": "14 Ft – 3 MT (14×6×6 ft)",
  "3": "19 Ft – 6 MT (19×6×6 ft)",
  "4": "22 Ft – 9 MT (22×7×7 ft)"
};

const containerSubTypeMap = {
  "1": "20 Ft Container",
  "2": "32 Ft Single Axle",
  "3": "32 Ft Multi Axle"
};

const truckSubTypeMap = {
  "1": "16 Ft Truck",
  "2": "19 Ft Truck",
  "3": "22 Ft Truck",
  "4": "24 Ft Truck"
};

// ================= STATE =================
let state = row.state || "start";

let oldData = {};
try {
  oldData = typeof row.data === "string" ? JSON.parse(row.data) : (row.data || {});
} catch {
  oldData = {};
}

let data = { ...oldData };
let response = "";

// ================= MAIN MENU =================
if (state === "main_menu") {

  if (message === "1") {
    state = "loading_pincode";
    data.flowType = "book";
    response = "📍 Please enter your *Loading Pincode* (6 digits)";
  }

  else if (message === "2") {
    state = "vp1_contact_name";
    data.flowType = "provider";
    response = "👤 Please enter *Driver Name*";
  }

  else if (message === "3") {
    state = "support_flow";
    data.flowType = "support";
    response = "*Hi, Welcome to Traket Transport*\n" +
                "*Please Contact on +91 9820500159 if your querry doesnt matches                     with the above two options*\n"+
                "Thank you so much for your precious time";       
  }

  else {
    response = "⚠️ Please reply with *1, 2 or 3*";
  }
}

// ================= PROVIDER FLOW =================
else if (state === "vp1_contact_name") {
  data.provider_driverName = message;
  state = "vp2_vehicle_type";
  response =
    "🚛 Select Vehicle Type:\n\n" +
    "1️⃣ Tempo\n" +
    "2️⃣ Truck\n" +
    "3️⃣ Container\n" +
    "4️⃣ Trailer / ODC\n\n" +
    "Reply with option number";
}

else if (state === "vp2_vehicle_type") {
  if (["1","2","3","4"].includes(message)) {
    data.provider_vehicleType = vehicleTypeMap[message];
    state = "vp3_vehicle_number";
    response = "🔢 Please enter *Vehicle Number*";
  } else {
    response = "⚠️ Enter *1, 2, 3 or 4* only";
  }
}

else if (state === "vp3_vehicle_number") {
  data.provider_vehicleNumber = message;
  state = "vp3_capacity";
  response = "⚖️ Enter *Vehicle Capacity*";
}

else if (state === "vp3_capacity") {
  data.provider_capacity = message;
  state = "vp3_routes";
  response = "🛣️ Enter *Operating Routes* (City to City)";
}

else if (state === "vp3_routes") {
  data.provider_routes = message;
  state = "vp3_availability";
  response = "📅 Enter *Available From Date*";
}

else if (state === "vp3_availability") {
  data.provider_availability = message;
  state = "vp_driver_phone";
  response = "📞 Enter *Driver Phone Number*";
}

else if (state === "vp_driver_phone") {
  data.provider_driverPhone = message;
  state = "vp_current_location";
  response = "📍 Enter *Current Location*";
}

else if (state === "vp_current_location") {
  data.provider_currentLocation = message;
  state = "vp_notes";
  response = "📝 Any additional notes? (Type *NA* if none)";
}

else if (state === "vp_notes") {
  data.provider_notes = message;
  state = "vp4_documents";
  response = "📄 Type *YES* if all documents are available (RC, Insurance, Permit)";
}

else if (state === "vp4_documents") {

  if (lowerMessage === "yes") {
    data.provider_documents = "YES";
    state = "cta_menu"; // ✅ changed

    response =
      "🚛 Vehicle Type: " + (data.provider_vehicleType || "") + "\n" +
      "📍 Routes: " + (data.provider_routes || "") + "\n" +
      "📅 Available From: " + (data.provider_availability || "") + "\n\n" +
      "Our operations team will contact you shortly for onboarding.\n" +
      "Thank you for partnering with us 🤝";

  } else {
    data.provider_documents = "NO";
    response = "⚠️ Please type *YES* to proceed";
  }
}

// ================= CUSTOMER FLOW =================
else if (state === "loading_pincode") {

  if (!/^[1-8][0-9]{5}$/.test(message)) {
    response = "❌ Invalid Pincode. Please enter a valid 6-digit pincode.";
  } else {
    data.loadingPin = message;
    state = "unloading_pincode";
    response = "📍 Please enter your *Unloading Pincode*";
  }
}

else if (state === "unloading_pincode") {

  if (!/^[1-8][0-9]{5}$/.test(message)) {
    response = "❌ Invalid Pincode. Please try again.";
  } else {
    data.unloadingPin = message;
    state = "cargo_type";
    response =
      "📦 Select Cargo Type:\n\n" +
      "1️⃣ Domestic\n" +
      "2️⃣ Import\n" +
      "3️⃣ Export\n\n" +
      "Reply with *1 / 2 / 3*";
  }
}

else if (state === "cargo_type") {

  if (["1","2","3"].includes(message)) {
    data.cargoType = cargoTypeMap[message];
    state = "vehicle_category";
    response =
      "🚛 Select Vehicle Type:\n\n" +
      "1️⃣ Tempo\n" +
      "2️⃣ Truck\n" +
      "3️⃣ Container\n" +
      "4️⃣ ODC\n\n" +
      "Reply with option number";
  } else {
    response = "⚠️ Enter *1, 2 or 3*";
  }
}

else if (state === "vehicle_category") {

  if (message === "1") {
    state = "tempo_type";
    response =
      "🚚 Please choose Tempo Size 👇\n\n" +
      "1️⃣ Pickup – 1 MT (8×5×5 ft)\n" +
      "2️⃣ 14 Ft – 3 MT (14×6×6 ft)\n" +
      "3️⃣ 19 Ft – 6 MT (19×6×6 ft)\n" +
      "4️⃣ 22 Ft – 9 MT (22×7×7 ft)\n\n" +
      "Reply with option number";
  }
  else if (message === "2") {
    state = "truck_type";
    response =
      "🚛 Please choose Truck Type 👇\n\n" +
      "1️⃣ 16 Ft Truck\n" +
      "2️⃣ 19 Ft Truck\n" +
      "3️⃣ 22 Ft Truck\n" +
      "4️⃣ 24 Ft Truck\n\n" +
      "Reply with option number";
  }
  else if (message === "3") {
    state = "container_type";
    response =
      "📦 Please select Container Type 🚢\n\n" +
      "1️⃣ 20 Ft Container\n" +
      "2️⃣ 32 Ft Single Axle\n" +
      "3️⃣ 32 Ft Multi Axle\n\n" +
      "Reply with option number";
  }
  else if (message === "4") {
    state = "odc_details";
    response = "⚠️ Enter ODC Details (Material, Size, Weight)";
  }
}

// ================= SUBTYPE =================
else if (state === "tempo_type") {

  if (tempoSubTypeMap[message]) {
    data.vehicleType = vehicleCategoryMap[state];
    data.vehicleSubType = tempoSubTypeMap[message];
    state = "material_details";
    response = "📦 Enter Material Details";
  } else {
    response = "⚠️ Please select a valid option (1-4)";
  }
}

else if (state === "container_type") {

  if (containerSubTypeMap[message]) {
    data.vehicleType = vehicleCategoryMap[state];
    data.vehicleSubType = containerSubTypeMap[message];
    state = "material_details";
    response = "📦 Enter Material Details";
  } else {
    response = "⚠️ Please select a valid option (1-3)";
  }
}

else if (state === "truck_type") {

  if (truckSubTypeMap[message]) {
    data.vehicleType = vehicleCategoryMap[state];
    data.vehicleSubType = truckSubTypeMap[message];
    state = "material_details";
    response = "📦 Enter Material Details";
  } else {
    response = "⚠️ Please select a valid option (1-4)";
  }
}

else if (state === "material_details") {
  data.material = message;
  state = "loading_date";
  response = "📅 Enter Loading Date";
}

else if (state === "loading_date") {
  data.loadingDate = message;
  state = "contact_details";
  response =
    "👤 Enter details in this format:\n\n" +
    "Company Name\n" +
    "Contact Name\n" +
    "Phone Number\n" +
    "Email ID\n" +
    "Website (or NA)";
}

else if (state === "contact_details") {

  const text = message;

  const phoneMatch = text.match(/\d{10}/);
  const phoneExtracted = phoneMatch ? phoneMatch[0] : "";

  const emailMatch = text.match(/\S+@\S+\.\S+/);
  const emailExtracted = emailMatch ? emailMatch[0] : "NA";

  let websiteExtracted = "NA";
  if (/www\.|http/.test(text)) {
    let webMatch = text.match(/(https?:\/\/[^\s]+|www\.[^\s]+)/);
    websiteExtracted = webMatch ? webMatch[0] : "NA";
  }

  let lines = text.split(/\n/).map(l => l.trim()).filter(Boolean);

  let company = "";
  let contactName = "";

  if (lines.length >= 3) {
    company = lines[0];
    contactName = lines[1];
  } else {
    let remaining = text
      .replace(phoneExtracted, "")
      .replace(emailExtracted, "")
      .replace(websiteExtracted, "")
      .trim();

    let parts = remaining.split(/,|-/).map(p => p.trim()).filter(Boolean);

    if (parts.length >= 2) {
      company = parts[0];
      contactName = parts[1];
    }
  }

  data.company = company;
  data.contactName = contactName;
  data.phone = phoneExtracted;
  data.email = emailExtracted;
  data.website = websiteExtracted;

  state = "cta_menu"; // ✅ changed

  response =
    "From :        " + (data.loadingPin || "") + "\n" +
    "To :          " + (data.unloadingPin || "") + "\n" +
    "Trip :        " + (data.cargoType || "") + "\n" +
    "Vehicle :     " + (data.vehicleType || "") + "\n" +
    "Sub vehicle : " + (data.vehicleSubType || "") + "\n" +
    "Goods type :  " + (data.material || "") + "\n" +
    "Loading Date :" + (data.loadingDate || "") + "\n\n" +
    "Name :" + (data.contactName || "") + "\n\n" +
    "Phone Number :" + (data.phone || "") + "\n\n" +
    "Thank you for Partnering with Us 🤝";
}

else if (state === "support_flow") {

  state = "cta_menu";

  response =
    "📞 Our support team will assist you shortly.\n\n" +
    "For urgent queries call: +91 9820500159\n\n" +
    "Thank you for contacting Traket 🤝";
}

// ================= CTA MENU =================
else if (state === "cta_menu") {

  if (message === "cta_new") {
    state = "main_menu";
    data = {};
    response =
      "🙏 *Welcome to Traket Transport* 🚛\n\n" +
      "We provide reliable logistics solutions across India 🇮🇳\n\n" +
      "👉 Please select your requirement:\n\n" +
      "1️⃣ Book a Vehicle (Customer)\n" +
      "2️⃣ Provide Vehicle (Transporter)\n" +
      "3️⃣ Support\n\n" +
      "Reply with *1, 2 or 3*";
  }

  else if (message === "cta_ai") {
    state = "ai_chat";
    response = "🤖 Ask me anything about Traket!";
  }

  else if (message === "cta_support") {
    state = "support_flow";
    response =
      "*Hi, Welcome to Traket Transport*\n" +
      "*Please Contact on +91 9820500159 if your querry doesnt matches                     with the above two options*\n"+
      "Thank you so much for your precious time";
  }

  else {
    response = "⚠️ Please select an option";
  }
}

// ================= DEFAULT =================
else {
  response = "👋 Type *Hi* to start again";
}

// ================= OUTPUT =================
const output = { ...row };

output.user_id = row.user_id || `${phone}_${Date.now()}`;
output.phone = phone;
output.state = state;
output.updated_at = new Date().toISOString();
output.response = response;

output.flowType = data.flowType ?? row.flowType ?? "";
output.data = JSON.stringify(data);

return [
  {
    json: output
  }
];

